     435: static int32_t aout_add_gsym_reloc(struct Section *sect,
     436:                                 int32_t segment, int32_t offset,
     437:                                 int type, int bytes, int exact)
     438: {
     439:     struct Symbol *sym, *sm, *shead;
     440:     struct Reloc *r;
     441: 
     442:     /*
     443:      * First look up the segment to find whether it's text, data,
     444:      * bss or an external symbol.
     445:      */
     446:     shead = NULL;
     447:     if (segment == stext.index)
     448:         shead = stext.gsyms;
     449:     else if (segment == sdata.index)
     450:         shead = sdata.gsyms;
     451:     else if (segment == sbss.index)
     452:         shead = sbss.gsyms;
     453:     if (!shead) {
     454:         if (exact && offset != 0)
     455:             nasm_nonfatal("unable to find a suitable global symbol"
     456:                           " for this reference");
     457:         else
     458:             aout_add_reloc(sect, segment, type, bytes);
     459:         return offset;
     460:     }
     461: 
     462:     if (exact) {
     463:         /*
     464:          * Find a symbol pointing _exactly_ at this one.
     465:          */
     466:         list_for_each(sym, shead)
     467:             if (sym->value == offset)
     468:                 break;
     469:         if (!sym) {
     470:             nasm_nonfatal("unable to find a suitable global symbol"
     471:                           " for this reference");
     472:             return 0;
     473:         }
     474:     } else {
     475:         /*
     476:          * Find the nearest symbol below this one.
     477:          */
     478:         sym = NULL;
     479:         list_for_each(sm, shead)
     480:             if (sm->value <= offset && (!sym || sm->value > sym->value))
     481:                 sym = sm;
     482:         if (!sym) {
     483:             nasm_nonfatal("unable to find a suitable nearest symbol"
     484:                           " below this reference");
     485:             return 0;
     486:         }
     487:     }
     488: 
>>   489:     r = *sect->tail = nasm_malloc(sizeof(struct Reloc));
     490:     sect->tail = &r->next;
     491:     r->next = NULL;
     492: 
     493:     r->address = sect->len;
     494:     r->symbol = sym->symnum;
     495:     r->reltype = type | RELTYPE_SYMFLAG;
     496:     r->bytes = bytes;
     497: 
     498:     sect->nrelocs++;
     499: 
     500:     return offset - sym->value;
     501: }

