     657: static int32_t elf_section_names(char *name, int *bits)
     658: {
     659:     char *p;
     660:     uint32_t flags, flags_and, flags_or;
     661:     uint64_t align, entsize;
     662:     void **hp;
     663:     struct elf_section *s;
     664:     struct hash_insert hi;
     665:     int type;
     666: 
     667:     if (!name) {
     668:         *bits = ofmt->maxbits;
     669:         return def_seg;
     670:     }
     671: 
     672:     p = nasm_skip_word(name);
     673:     if (*p)
     674:         *p++ = '\0';
     675:     flags_and = flags_or = type = align = entsize = 0;
     676: 
     677:     elf_section_attrib(name, p, &flags_and, &flags_or, &align, &entsize, &type);
     678: 
     679:     hp = hash_find(&section_by_name, name, &hi);
     680:     if (hp) {
     681:         s = *hp;
     682:         if (!s) {
     683:             nasm_nonfatal("attempt to redefine reserved section name `%s'", name);
     684:             return NO_SEG;
     685:         }
     686:     } else {
     687:         const struct elf_known_section *ks = elf_known_sections;
     688: 
     689:         while (ks->name) {
     690:             if (!strcmp(name, ks->name))
     691:                 break;
     692:             ks++;
     693:         }
     694: 
     695:         type = type ? type : ks->type;
     696: 	if (!align)
     697: 	    align = to_bytes(ks->align);
     698: 	if (!entsize)
     699: 	    entsize = to_bytes(ks->entsize);
     700:         flags = (ks->flags & ~flags_and) | flags_or;
     701: 
>>   702:         s = elf_make_section(name, type, flags, align);
     703:         hash_add(&hi, s->name, s);
     704:         section_by_index = raa_write_ptr(section_by_index, s->index >> 1, s);
     705:     }
     706: 
     707:     if ((type && s->type != type)
     708:         || ((s->flags & flags_and) != flags_or)
     709:         || (entsize && s->entsize && entsize != s->entsize)) {
     710:         nasm_warn(WARN_OTHER, "incompatible section attributes ignored on"
     711:                   " redeclaration of section `%s'", name);
     712:     }
     713: 
     714:     if (align > s->align)
     715:         s->align = align;
     716: 
     717:     if (entsize && !s->entsize)
     718:         s->entsize = entsize;
