     636:         *bits = 16;
     637:         if (!any_segs)
     638:             return 0;
     639:         return seghead->index;
     640:     } else {
     641:         struct ieeeSection *seg;
     642:         int ieee_idx, attrs;
     643: 	bool rn_error;
     644:         char *p;
     645: 
     646:         /*
     647:          * Look for segment attributes.
     648:          */
     649:         attrs = 0;
     650:         while (*name == '.')
     651:             name++;             /* hack, but a documented one */
     652:         p = name;
     653:         while (*p && !nasm_isspace(*p))
     654:             p++;
     655:         if (*p) {
     656:             *p++ = '\0';
     657:             while (*p && nasm_isspace(*p))
     658:                 *p++ = '\0';
     659:         }
     660:         while (*p) {
     661:             while (*p && !nasm_isspace(*p))
     662:                 p++;
     663:             if (*p) {
     664:                 *p++ = '\0';
     665:                 while (*p && nasm_isspace(*p))
     666:                     *p++ = '\0';
     667:             }
     668: 
     669:             attrs++;
     670:         }
     671: 
     672:         ieee_idx = 1;
     673:         for (seg = seghead; seg; seg = seg->next) {
     674:             ieee_idx++;
     675:             if (!strcmp(seg->name, name)) {
     676:                 if (attrs > 0 && seg->pass_last_seen == pass_count())
     677:                     nasm_warn(WARN_OTHER, "segment attributes specified on"
     678:                               " redeclaration of segment: ignoring");
     679:                 if (seg->use32)
     680:                     *bits = 32;
     681:                 else
     682:                     *bits = 16;
     683: 
     684:                 seg->pass_last_seen = pass_count();
     685:                 return seg->index;
     686:             }
     687:         }
     688: 
>>   689:         *segtail = seg = nasm_malloc(sizeof(*seg));
     690:         seg->next = NULL;
     691:         segtail = &seg->next;
     692:         seg->index = seg_alloc();
     693:         seg->ieee_index = ieee_idx;
     694:         any_segs = true;
     695:         seg->name = NULL;
     696:         seg->currentpos = 0;
     697:         seg->align = 1;         /* default */
     698:         seg->use32 = *bits == 32;       /* default to user spec */
