     739:                 case 2:        /* WORD */
     740:                 case 4:        /* DWORD */
     741:                 case 16:       /* PARA */
     742:                 case 256:      /* PAGE */
     743:                 case 8:
     744:                 case 32:
     745:                 case 64:
     746:                 case 128:
