     763:             define_label(name, NO_SEG, seg->align - SEG_ABS, false);
     764:         else
     765:             define_label(name, seg->index + 1, 0L, false);
     766:         ieee_seg_needs_update = NULL;
     767: 
     768:         /*
     769:          * In commit 98578071b9d71ecaa2344dd9c185237c1765041e
     770:          * we reworked labels significantly which in turn lead
     771:          * to the case where seg->name = NULL here and we get
     772:          * nil dereference in next segments definitions.
     773:          *
     774:          * Lets placate this case with explicit name setting
     775:          * if labels engine didn't set it yet.
     776:          *
     777:          * FIXME: Need to revisit this moment if such fix doesn't
     778:          * break anything but since IEEE 695 format is veeery
     779:          * old I don't expect there are many users left. In worst
     780:          * case this should only lead to a memory leak.
     781:          */
     782:         if (!seg->name)
     783:             seg->name = nasm_strdup(name);
     784: 
     785:         if (seg->use32)
     786:             *bits = 32;
     787:         else
     788:             *bits = 16;
     789:         return seg->index;
     790:     }
     791: }

