     626: static int32_t ieee_segment(char *name, int *bits)
     627: {
     628:     /*
     629:      * We call the label manager here to define a name for the new
     630:      * segment, and when our _own_ label-definition stub gets
     631:      * called in return, it should register the new segment name
     632:      * using the pointer it gets passed. That way we save memory,
     633:      * by sponging off the label manager.
     634:      */
     635:     if (!name) {
     636:         *bits = 16;
     637:         if (!any_segs)
     638:             return 0;
     639:         return seghead->index;
     640:     } else {
     641:         struct ieeeSection *seg;
     642:         int ieee_idx, attrs;
     643: 	bool rn_error;
     644:         char *p;
     645: 
     646:         /*
     647:          * Look for segment attributes.
     648:          */
     649:         attrs = 0;
     650:         while (*name == '.')
     651:             name++;             /* hack, but a documented one */
     652:         p = name;
     653:         while (*p && !nasm_isspace(*p))
     654:             p++;
     655:         if (*p) {
     656:             *p++ = '\0';
     657:             while (*p && nasm_isspace(*p))
     658:                 *p++ = '\0';
     659:         }
     660:         while (*p) {
     661:             while (*p && !nasm_isspace(*p))
     662:                 p++;
     663:             if (*p) {
     664:                 *p++ = '\0';
     665:                 while (*p && nasm_isspace(*p))
     666:                     *p++ = '\0';
     667:             }
     668: 
     669:             attrs++;
     670:         }
     671: 
     672:         ieee_idx = 1;
     673:         for (seg = seghead; seg; seg = seg->next) {
     674:             ieee_idx++;
     675:             if (!strcmp(seg->name, name)) {
     676:                 if (attrs > 0 && seg->pass_last_seen == pass_count())
     677:                     nasm_warn(WARN_OTHER, "segment attributes specified on"
     678:                               " redeclaration of segment: ignoring");
     679:                 if (seg->use32)
     680:                     *bits = 32;
     681:                 else
     682:                     *bits = 16;
     683: 
     684:                 seg->pass_last_seen = pass_count();
     685:                 return seg->index;
     686:             }
     687:         }
     688: 
>>   689:         *segtail = seg = nasm_malloc(sizeof(*seg));
     690:         seg->next = NULL;
     691:         segtail = &seg->next;
     692:         seg->index = seg_alloc();
     693:         seg->ieee_index = ieee_idx;
     694:         any_segs = true;
     695:         seg->name = NULL;
     696:         seg->currentpos = 0;
     697:         seg->align = 1;         /* default */
     698:         seg->use32 = *bits == 32;       /* default to user spec */
     699:         seg->combine = CMB_PUBLIC;      /* default */
     700:         seg->pubhead = NULL;
     701:         seg->pubtail = &seg->pubhead;
     702:         seg->data = NULL;
     703:         seg->fptr = NULL;
     704:         seg->lochead = NULL;
     705:         seg->loctail = &seg->lochead;
     706: 
     707:         /*
     708:          * Process the segment attributes.
     709:          */
     710:         p = name;
     711:         while (attrs--) {
     712:             p += strlen(p);
     713:             while (!*p)
     714:                 p++;
     715: 
     716:             /*
     717:              * `p' contains a segment attribute.
     718:              */
     719:             if (!nasm_stricmp(p, "private"))
     720:                 seg->combine = CMB_PRIVATE;
     721:             else if (!nasm_stricmp(p, "public"))
     722:                 seg->combine = CMB_PUBLIC;
     723:             else if (!nasm_stricmp(p, "common"))
     724:                 seg->combine = CMB_COMMON;
     725:             else if (!nasm_stricmp(p, "use16"))
     726:                 seg->use32 = false;
     727:             else if (!nasm_stricmp(p, "use32"))
     728:                 seg->use32 = true;
     729:             else if (!nasm_strnicmp(p, "align=", 6)) {
     730:                 seg->align = readnum(p + 6, &rn_error);
     731:                 if (seg->align == 0)
     732:                     seg->align = 1;
     733:                 if (rn_error) {
     734:                     seg->align = 1;
     735:                     nasm_nonfatal("segment alignment should be numeric");
     736:                 }
     737:                 switch (seg->align) {
     738:                 case 1:        /* BYTE */
     739:                 case 2:        /* WORD */
     740:                 case 4:        /* DWORD */
     741:                 case 16:       /* PARA */
     742:                 case 256:      /* PAGE */
     743:                 case 8:
     744:                 case 32:
     745:                 case 64:
     746:                 case 128:
     747:                     break;
     748:                 default:
     749:                     nasm_nonfatal("invalid alignment value %d", seg->align);
     750:                     seg->align = 1;
     751:                     break;
     752:                 }
     753:             } else if (!nasm_strnicmp(p, "absolute=", 9)) {
     754:                 seg->align = SEG_ABS + readnum(p + 9, &rn_error);
     755:                 if (rn_error)
     756:                     nasm_nonfatal("argument to `absolute' segment"
     757:                                   " attribute should be numeric");
     758:             }
     759:         }
     760: 
     761:         ieee_seg_needs_update = seg;
     762:         if (seg->align >= SEG_ABS)
     763:             define_label(name, NO_SEG, seg->align - SEG_ABS, false);
     764:         else
     765:             define_label(name, seg->index + 1, 0L, false);
     766:         ieee_seg_needs_update = NULL;
     767: 
     768:         /*
     769:          * In commit 98578071b9d71ecaa2344dd9c185237c1765041e
     770:          * we reworked labels significantly which in turn lead
     771:          * to the case where seg->name = NULL here and we get
     772:          * nil dereference in next segments definitions.
     773:          *
     774:          * Lets placate this case with explicit name setting
     775:          * if labels engine didn't set it yet.
     776:          *
     777:          * FIXME: Need to revisit this moment if such fix doesn't
     778:          * break anything but since IEEE 695 format is veeery
     779:          * old I don't expect there are many users left. In worst
     780:          * case this should only lead to a memory leak.
     781:          */
     782:         if (!seg->name)
     783:             seg->name = nasm_strdup(name);
     784: 
     785:         if (seg->use32)
     786:             *bits = 32;
     787:         else
     788:             *bits = 16;
     789:         return seg->index;
     790:     }
     791: }

